class Solution {
    public boolean[] friendRequests(int n, int[][] restrictions, int[][] requests) {
        UnionFind uf = new UnionFind(n);
        boolean[] result = new boolean[requests.length];
        for (int i = 0; i < requests.length; i++) {
            int u = requests[i][0], v = requests[i][1];
            if (uf.find(u) != uf.find(v) && !isRestricted(uf, restrictions, u, v)) {
                uf.union(u, v);
                result[i] = true;
            }
        }
        return result;
    }

    private boolean isRestricted(int[][] restrictions, UnionFind uf, int u, int v) {
        for (int[] r : restrictions) {
            if ((uf.find(u) == uf.find(r[0]) && uf.find(v) == uf.find(r[1])) ||
                (uf.find(u) == uf.find(r[1]) && uf.find(v) == uf.find(r[0]))) {
                return true;
            }
        }
        return false;
    }

    class UnionFind {
        int[] parent;

        public UnionFind(int n) {
            parent = new int[n];
            for (int i = 0; i < n; i++) {
                parent[i] = i;
            }
        }

        public int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        public void union(int x, int y) {
            int rootX = find(x), rootY = find(y);
            if (rootX != rootY) {
                parent[rootX] = rootY;
            }
        }
    }
}
